  create policy "Users can update own basic profile fields"
  on "public"."user_profiles"
  as permissive
  for update
  to public
using ((auth.uid() = user_id))
with check (((auth.uid() = user_id) AND (payment_status = ( SELECT up.payment_status
   FROM public.user_profiles up
  WHERE (up.user_id = auth.uid())))));



  create policy "Users can view own profile"
  on "public"."user_profiles"
  as permissive
  for select
  to public
using ((auth.uid() = user_id));


CREATE TRIGGER on_user_profile_payment_status_changed AFTER UPDATE OF payment_status ON public.user_profiles FOR EACH ROW WHEN ((old.payment_status IS DISTINCT FROM new.payment_status)) EXECUTE FUNCTION public.sync_user_payment_claims();

CREATE TRIGGER on_auth_user_created_user_profile AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user_profile();


